// Redis client
const redis = new Redis({
  host: process.env.REDIS_HOST || '127.0.0.1',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD || undefined,
  tls: process.env.REDIS_TLS === 'true' ? {} : undefined,
});

// Configuration
const CONFIG = {
  ACCESS_TOKEN_EXPIRY: 15 * 60, // 15 minutes in seconds
  REFRESH_TOKEN_EXPIRY: 365 * 24 * 60 * 60, // 1 year in seconds
  JWT_SECRET: process.env.JWT_SECRET || crypto.randomBytes(64).toString('hex'),
  JWT_ISSUER: 'oauth2-server',
  BCRYPT_ROUNDS: 12,
  REFRESH_TOKEN_BYTES: 48, // 384 bits of entropy
  MAX_REFRESH_TOKENS_PER_USER: 10,
  AUTHORIZATION_CODE_EXPIRY: 600, // 10 minutes
  PKCE_REQUIRED: true,
};

// Rate limiters
const tokenRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 30,
  message: { error: 'too_many_requests', error_description: 'Rate limit exceeded' },
  standardHeaders: true,
  legacyHeaders: false,
});

const authRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 20,
  message: { error: 'too_many_requests', error_description: 'Rate limit exceeded' },
  standardHeaders: true,
  legacyHeaders: false,
});

