// --- Helper Functions ---

function generateSecureToken(bytes = CONFIG.REFRESH_TOKEN_BYTES) {
  return crypto.randomBytes(bytes).toString('base64url');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

function generateAuthorizationCode() {
  return crypto.randomBytes(32).toString('base64url');
}

function generateAccessToken(payload) {
  return jwt.sign(payload, CONFIG.JWT_SECRET, {
    expiresIn: CONFIG.ACCESS_TOKEN_EXPIRY,
    issuer: CONFIG.JWT_ISSUER,
    jwtid: uuidv4(),
  });
}

function verifyAccessToken(token) {
  return jwt.verify(token, CONFIG.JWT_SECRET, {
    issuer: CONFIG.JWT_ISSUER,
  });
}

function generateCodeChallenge(codeVerifier) {
  return crypto.createHash('sha256').update(codeVerifier).digest('base64url');
}

function validateRedirectUri(clientRedirectUris, requestedUri) {
  return clientRedirectUris.includes(requestedUri);
}

function validateScope(requestedScopes, allowedScopes) {
  const requested = requestedScopes.split(' ').filter(Boolean);
  const allowed = new Set(allowedScopes);
  return requested.every((s) => allowed.has(s));
}

// --- Redis operations for refresh tokens ---

async function storeRefreshToken(tokenHash, tokenData) {
  const key = `refresh_token:${tokenHash}`;
  await redis.setex(key, CONFIG.REFRESH_TOKEN_EXPIRY, JSON.stringify(tokenData));

  // Track tokens per user for limiting
  const userTokensKey = `user_tokens:${tokenData.userId}`;
  await redis.sadd(userTokensKey, tokenHash);
  await redis.expire(userTokensKey, CONFIG.REFRESH_TOKEN_EXPIRY);

  // Enforce max tokens per user
  const tokenCount = await redis.scard(userTokensKey);
  if (tokenCount > CONFIG.MAX_REFRESH_TOKENS_PER_USER) {
    const allTokens = await redis.smembers(userTokensKey);
    // Remove oldest tokens (those that have shortest remaining TTL)
    const tokenTTLs = await Promise.all(
      allTokens.map(async (th) => ({
        hash: th,
        ttl: await redis.ttl(`refresh_token:${th}`),
      }))
    );
    tokenTTLs.sort((a, b) => a.ttl - b.ttl);
    const toRemove = tokenTTLs.slice(0, tokenCount - CONFIG.MAX_REFRESH_TOKENS_PER_USER);
    for (const t of toRemove) {
      await redis.del(`refresh_token:${t.hash}`);
      await redis.srem(userTokensKey, t.hash);
    }
  }
}

async function getRefreshToken(tokenHash) {
  const key = `refresh_token:${tokenHash}`;
  const data = await redis.get(key);
  if (!data) return null;
  return JSON.parse(data);
}

async function revokeRefreshToken(tokenHash) {
  const key = `refresh_token:${tokenHash}`;
  const data = await redis.get(key);
  if (data) {
    const tokenData = JSON.parse(data);
    await redis.srem(`user_tokens:${tokenData.userId}`, tokenHash);
  }
  await redis.del(key);
}

async function revokeAllUserTokens(userId) {
  const userTokensKey = `user_tokens:${userId}`;
  const allTokens = await redis.smembers(userTokensKey);
  const pipeline = redis.pipeline();
  for (const th of allTokens) {
    pipeline.del(`refresh_token:${th}`);
  }
  pipeline.del(userTokensKey);
  await pipeline.exec();
}

async function storeAuthorizationCode(code, codeData) {
  const codeHash = hashToken(code);
  const key = `auth_code:${codeHash}`;
  await redis.setex(key, CONFIG.AUTHORIZATION_CODE_EXPIRY, JSON.stringify(codeData));
}

async function consumeAuthorizationCode(code) {
  const codeHash = hashToken(code);
  const key = `auth_code:${codeHash}`;
  const data = await redis.get(key);
  if (!data) return null;
  // Authorization codes are single-use
  await redis.del(key);
  return JSON.parse(data);
}

// Track used jti to prevent replay of access tokens at revocation
async function blacklistAccessToken(jti, expiresIn) {
  await redis.setex(`blacklisted_jwt:${jti}`, expiresIn, '1');
}

async function isAccessTokenBlacklisted(jti) {
  return (await redis.exists(`blacklisted_jwt:${jti}`)) === 1;
}

