// --- Client Authentication Middleware ---

async function authenticateClient(req) {
  let clientId, clientSecret;

  // Check Authorization header (client_secret_basic)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
    const colonIndex = decoded.indexOf(':');
    if (colonIndex === -1) return null;
    clientId = decodeURIComponent(decoded.slice(0, colonIndex));
    clientSecret = decodeURIComponent(decoded.slice(colonIndex + 1));
  }

  // Check body (client_secret_post)
  if (!clientId && req.body.client_id) {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret || null;
  }

  if (!clientId) return null;

  const client = clients.get(clientId);
  if (!client) return null;

  // For confidential clients, verify secret
  if (client.isConfidential) {
    if (!clientSecret) return null;
    const valid = await bcrypt.compare(clientSecret, client.clientSecretHash);
    if (!valid) return null;
  }

  return client;
}

